// GOOD: consistent lock ordering prevents deadlock
public void transfer(Account from, Account to, int amount) {
    Account first = from.getId() < to.getId() ? from : to;
    Account second = from.getId() < to.getId() ? to : from;
    synchronized (first) {
        synchronized (second) {
            from.debit(amount);
            to.credit(amount);
        }
    }
}

// BAD: terrible hashCode - all keys in one bucket
public class BadKey {
    private String name;
    @Override public int hashCode() { return 1; } // everything collides!
    @Override public boolean equals(Object o) { ... }
}

// GOOD: well-distributed hashCode
public class GoodKey {
    private String name;
    private int id;
    private String type;

    @Override
    public int hashCode() {
        return Objects.hash(name, id, type); // prime multiplication, good spread
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof GoodKey)) return false;
        GoodKey k = (GoodKey) o;
        return id == k.id && Objects.equals(name, k.name) && Objects.equals(type, k.type);
    }
}

