// BAD: ThreadLocal without cleanup -> state leak between requests
private static ThreadLocal<UserContext> ctx = new ThreadLocal<>();

public void handleRequest(User user) {
    ctx.set(new UserContext(user));
    processRequest(); // if this throws, cleanup is skipped!
    ctx.remove(); // may not be reached
}

// GOOD: always clean up in finally
public void handleRequest(User user) {
    ctx.set(new UserContext(user));
    try {
        processRequest();
    } finally {
        ctx.remove(); // always executed, prevents leakage
    }
}

