// Livelock example
class Corridor {
    volatile boolean moving = true;
    void pass(Corridor other) {
        while (other.moving) {
            this.moving = false; // yield
            Thread.yield();
            this.moving = true;  // try again
            // Both keep yielding -> livelock
        }
    }
}

